{%- comment -%} 
  Build a JS object literal mapping variant IDs → labels 
  (capture tag must be given a bare variable name, not in quotes) 
{%- endcomment -%}
{% capture meta_data %}
{%- for variant in product.variants -%}
  "{{ variant.id }}": {{ variant.metafields.custom.notify_me_button_label | json }}
  {%- unless forloop.last -%},{%- endunless -%}
{%- endfor -%}
{% endcapture %}

<script>
  // Convert captured string into a real JS object
  const metaData = { {{ meta_data | strip }} };

  document.addEventListener("DOMContentLoaded", () => {
    const selector = document.querySelector('input[name="id"]');
    const meta     = document.querySelector('#test');

    // Pull the current variant ID, look up its label, and swap it in
    function updateMetaField() {
      const variantId = selector ? selector.value : null;
      if (variantId && metaData[variantId]) {
        meta.innerHTML = metaData[variantId];
        meta.classList.add('added');
      }
    }

    // Run once on load…
    updateMetaField();
    // …then every second as a fallback in case Shopify re-renders
    setInterval(updateMetaField, 1000);
  });
</script>

{%- comment -%}
  1) Detect wholesale customers by tag
  2) Only render the notice & JS if is_wholesale == true
{%- endcomment -%}
{% assign wholesale_tags = "Wholesale-Gold,Wholesale-Silver,Wholesale-Bronze,gold-dealer,silver-dealer,bronze-dealer" | split: "," %}
{% assign is_wholesale = false %}
{% if customer %}
  {% for tag in wholesale_tags %}
    {% if customer.tags contains tag %}
      {% assign is_wholesale = true %}
      {% break %}
    {% endif %}
  {% endfor %}
{% endif %}

{% if is_wholesale %}
  <!-- 1) Placeholder (start hidden) -->
  <div
    id="preprod-notice"
    class="product__text rte text-sm"
    style="display:none; margin-top:1em;"
  ></div>

  <!-- 2) Build your variant→note map -->
  {% capture preprod_map %}
  {
    {% for variant in product.variants %}
      "{{ variant.id }}": {{ variant.metafields.custom.preproduction_note | json }}{% unless forloop.last %},{% endunless %}
    {% endfor %}
  }
  {% endcapture %}

  <script>
    document.addEventListener('DOMContentLoaded', function(){
      // Only runs for wholesale (because of the Liquid guard above)
      var preprodMap = {{ preprod_map }};
      var selector   = document.querySelector('input[name="id"]');
      var noticeEl   = document.getElementById('preprod-notice');

      function updateNotice(){
        if (!selector || !noticeEl) return;
        var txt = preprodMap[ selector.value ];
        if (txt) {
          noticeEl.innerHTML      = txt;
          noticeEl.style.display  = 'block';
        } else {
          noticeEl.style.display  = 'none';
        }
      }

      // fire on page-load + variant-change
      updateNotice();
      if (selector) {
        selector.addEventListener('change', updateNotice);
      }
    });
  </script>
{% endif %}

